    on(container, "pointerleave", () => this._scheduleHide());
    on(container, "pointerdown", (e) => this._onPointerDown(e));
    on(container, "pointerup", (e) => this._onPointerUp(e));
    on(container, "pointercancel", () => this._cancelHold());
